parameters.jsCode:
const estoque = $input.first().json;
const ops = $('Consultar Ordens de Produção').all().map(i => i.json);

const opsDoMaterial = ops.filter(op => op.material === estoque.id);
const demandaTotal = opsDoMaterial.reduce((sum, op) => sum + op.quantidade, 0);
const deficit = estoque.quantidade - demandaTotal;
const quantidadeReposicao = Math.max(estoque.maximo - estoque.quantidade, Math.abs(deficit));

return [{
  json: {
    material: estoque.id,
    nome: estoque.nome,
    quantidadeAtual: estoque.quantidade,
    minimo: estoque.minimo,
    maximo: estoque.maximo,
    demandaOPs: demandaTotal,
    deficit: deficit,
    quantidadeReposicao: quantidadeReposicao,
    opsVinculadas: opsDoMaterial.length,
    opsDetalhes: opsDoMaterial,
    localizacao: estoque.localizacao,
    unidade: estoque.unidade
  }
}];

